INSERT INTO posts (mssv, title, content, image_url, video_url) VALUES
('22100001', 'First week at the library', 'Spent the afternoon reviewing database normalization and writing summary notes for the group. The quiet corner near the window is now my favorite place to study.', 'https://images.unsplash.com/photo-1522202176988-66273c2fd55f?auto=format&fit=crop&w=1200&q=80', NULL),
('22100001', 'Chia sẻ tài liệu môn Cơ sở dữ liệu', 'Mình vừa tổng hợp lại các khái niệm về khóa chính, khóa ngoại, chuẩn hóa dữ liệu và một số bài tập cơ bản để mọi người ôn tập tốt hơn.', 'https://images.unsplash.com/photo-1513258496099-48168024aec0?auto=format&fit=crop&w=1200&q=80', NULL),
('22100001', 'Cafe coding after class', 'After class, I went to a coffee shop to debug a pagination issue in Spring Boot. The bug was small, but finding it took almost two hours.', 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&w=1200&q=80', NULL),

('22100002', 'Morning run before class', 'Started the day with a short run around campus and felt much more focused during the operating systems lecture.', 'https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=1200&q=80', NULL),
('22100002', 'Kinh nghiệm học nhóm hiệu quả', 'Theo mình, học nhóm chỉ hiệu quả khi mọi người chuẩn bị trước câu hỏi và chia rõ phần thảo luận. Nếu không thì rất dễ ngồi đông nhưng không giải quyết được gì.', 'https://images.unsplash.com/photo-1523240795612-9a054b0db644?auto=format&fit=crop&w=1200&q=80', NULL),
('22100002', 'UI draft for roommate finder', 'I sketched a simple mobile UI for a roommate finder app with filters for budget, district, and study habits.', 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?auto=format&fit=crop&w=1200&q=80', NULL),

('22100003', 'Hackathon preparation night', 'Our team listed possible ideas for the weekend hackathon, including a dorm service app and a note sharing platform for students.', 'https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&w=1200&q=80', NULL),
('22100003', 'Lần đầu thuyết trình bằng tiếng Anh', 'Ban đầu mình khá run nhưng sau vài phút thì đỡ hơn nhiều. Sau buổi đó mình nhận ra luyện nói mỗi ngày thật sự rất quan trọng.', 'https://images.unsplash.com/photo-1522202176988-66273c2fd55f?auto=format&fit=crop&w=1200&q=80', 'https://samplelib.com/lib/preview/mp4/sample-5s.mp4'),
