('22100004', 'Volunteer day at the library', 'Joined a volunteer team to rearrange old books and help freshmen find references for their first assignments.', 'https://images.unsplash.com/photo-1507842217343-583bb7270b66?auto=format&fit=crop&w=1200&q=80', NULL),
('22100004', 'Bài học sau lần push nhầm branch', 'Hôm nay mình lỡ push code lên sai branch. Sau vụ này chắc chắn phải kiểm tra branch hiện tại kỹ hơn trước khi commit và push.', 'https://images.unsplash.com/photo-1516321310764-8d4b0d0b0b4b?auto=format&fit=crop&w=1200&q=80', NULL),
('22100004', 'Simple dorm expense tracker', 'Built a small tracker to split electricity, water, and internet fees among roommates. It is simple but useful.', 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?auto=format&fit=crop&w=1200&q=80', NULL),

('22100005', 'First mock interview experience', 'Tried a mock backend interview today. I did well on SQL joins but struggled a bit with transaction isolation.', 'https://images.unsplash.com/photo-1517048676732-d65bc937f952?auto=format&fit=crop&w=1200&q=80', NULL),
('22100005', 'Chụp ảnh hoàng hôn ở sân trường', 'Chiều nay trời đẹp nên mình tranh thủ chụp vài tấm ảnh ở sân trường sau giờ học. Ánh nắng cuối ngày làm mọi thứ nhìn yên bình hơn.', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', NULL),
('22100005', 'Building a personal portfolio site', 'I started a portfolio website to collect my projects, internship goals, and achievements from the last two years.', 'https://images.unsplash.com/photo-1461749280684-dccba630e2f6?auto=format&fit=crop&w=1200&q=80', NULL),

('22100006', 'Weekend badminton match', 'Played badminton with classmates after finishing the weekly tasks. It was a good break after several days of coding.', 'https://images.unsplash.com/photo-1546519638-68e109498ffc?auto=format&fit=crop&w=1200&q=80', NULL),
('22100006', 'Chuyện nhỏ ở căn tin trường', 'Hôm nay căn tin khá đông nhưng mình vẫn kịp ăn trưa trước giờ vào lớp. Tình cờ gặp mấy bạn khóa dưới hỏi về lộ trình học web backend.', 'https://images.unsplash.com/photo-1466978913421-dad2ebd01d17?auto=format&fit=crop&w=1200&q=80', NULL),
('22100006', 'Learning Git rebase carefully', 'I spent the night practicing git rebase on a demo repository so I would not break the team history in the real project.', 'https://images.unsplash.com/photo-1516321497487-e288fb19713f?auto=format&fit=crop&w=1200&q=80', NULL),

('22100007', 'Study plan for midterm week', 'Made a realistic study plan for the midterm week by splitting large subjects into smaller review blocks.', 'https://images.unsplash.com/photo-1455390582262-044cdead277a?auto=format&fit=crop&w=1200&q=80', NULL),
('22100007', 'Ôn tập môn Mạng máy tính', 'Mình đang tổng hợp lại TCP, UDP, địa chỉ IP, subnet mask và mô hình OSI để chuẩn bị cho bài kiểm tra tuần tới.', 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&w=1200&q=80', NULL),
